DROP VIEW "public"."domain_tags_with_nft_and_order_items_view";--> statement-breakpoint
ALTER TABLE "order_items" ADD COLUMN "duration_in_years" integer;--> statement-breakpoint
CREATE VIEW "public"."domain_tags_with_nft_and_order_items_view" AS (select "domain_tags"."tag", "namefi_nft"."chain_id", "namefi_nft"."owner_address", "namefi_nft"."as_of_block_number", "order_items"."id", "order_items"."order_id", "order_items"."normalized_domain_name", "order_items"."amount_in_usd_cents", "order_items"."duration_in_years", "order_items"."status", "order_items"."metadata", "order_items"."created_at", "order_items"."updated_at", orders.status as "order_status", orders.user_id as "order_user_id", orders.payment_id as "order_payment_id" from "domain_tags" left join "namefi_nft" on "domain_tags"."normalized_domain_name" = "namefi_nft"."normalized_domain_name" left join "order_items" on "domain_tags"."normalized_domain_name" = "order_items"."normalized_domain_name" left join "orders" on "order_items"."order_id" = "orders"."id" order by "order_items"."created_at" asc, "domain_tags"."normalized_domain_name" asc);